export const getTotalRevenue = () => mockSales.reduce((sum, sale) => sum + sale.total_sales, 0);
export const getTotalprofit = () => mockSales.reduce((sum, sale) => sum + sale.profit, 0);
export const getTotalOrders = () => mockSales.length;
export const getAverageOrderValue = () => getTotalRevenue() / getTotalOrders();
